# Convert YYYY-MM-DD to epoch seconds (portable: uses date -d)
date_to_epoch() {
    date -d "$1" +%s 2>/dev/null || die "Invalid date: $1"
}

input.new_string:
# Convert YYYY-MM-DD to epoch seconds. Force UTC to avoid DST skew.
date_to_epoch() {
    TZ=UTC date -d "$1" +%s 2>/dev/null || die "Invalid date: $1"
}

